INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (1035, 167605, 6, 1238, '生死不过刹那间', '以为咖啡早就不存在了，没想到是换了一个名字，也就是说，它只是换了一个存在方式而已。
<br>但是一上来就看到这里有人要生要死的。嗯，生存还是死亡，的确是个问题。但是我还是大家能活下去，那怕稀里糊涂也好。‘你不是我怎知我错’一定有人感觉不爽，其实我也不爽，我自己也找不到天堂之路嘛。
<br>就死而论死，仔细回想一下，其实也有蛮多次面临生死擦肩的际遇的，可是我还是没有能够成为大富大贵，看长相就知道－－‘乞丐命啦’（世界杯开幕那天在小巴上，那个漂亮的售票小姐这样形容她自己，我还能怎样形容自己）。
<br>很小的时候，应该是还没有什么智力可言的时候，我掉进了一个池塘里，模模糊糊只记得一班小孩子七手八脚把我从一个脏水沟里把我拉出来，也许是捞出来吧，我的童年好像就是从那时开始的，反正这之前并没有什么记忆存在，但我活了。
<br>小孩子们总是莫名其妙的分成了两派，打架，有点武侠小说里江湖的味道，显然我从小就没有领导的风范，所以他们就常来捡白肉，甚至到了舞枪弄剑的架式，奇怪的是竟然没人能在我身上留下什么记号。但是有一次是真正的死亡威胁，而我不知道。我在废弃的一个弹药库房边捡到了几支雷管，还有压发式地雷引信，当时觉得挺好玩的，用力一压，那个有机玻璃柱子里就会弹出一支钢针‘啪’牢牢钉在门板上，我想可以用来对付那些想捡便宜的家伙。但我不懂得那紫红色的铝管有什么用－－玻璃柱子的孔比管子大一些，装不到一起。有个伙伴觉得铝管好玩，就要了几个拿回家。结果让他老爸狠k了一顿，才知道那是雷管，而洽在附近的村庄，就有人被雷管炸的只剩一条大腿的。后来识字了，才在一本部队的发黄的小册子上看到那是一套地雷引信，好像还是反装甲的呢。如果不是被识破，凭我那钻牛角尖的劲头，迟早要造出一朵蘑菇云来。
<br>小时候常常感觉头上好像压着一块乌云，挥之不去。老去卫生所里，打针、吃药，后来才知道自己得的是百日咳，一天到晚喉咙里象有个东西在抓着，睡觉要拿条围巾绑在脖子上，真是生不如死。于是我开始看医书，尽管识字不多，却也认了不少草药－－有种叫三桠苦的可以治，但是不易识别，我也找不到，倒是让我发现一种毒药随处可见，叶子晒干验成粉只要35毫克就可致命，（而且死装看起来象心脏病发作，真乃行走江湖，杀人越货之必备良药也，以后看谁不爽，就把它当成胡椒粉请他吃顿饭）真难想象，她开的花还是蛮灿烂的。西药好像没有效果，就胡乱吃着各种‘民间秘方’－－不过冰糖、桃李之类，居然也不知不觉好了。 
<br>但让我真正体会要死的感觉的却是俗称的‘缠身蛇’，不知这社会上怎有那么多庸医，还是正规医院呢，看了两家，又打针又吃药，开的药就西医来说应当是正确的，但最终我感觉自己没法撑下去了。只好请我的老乡赶快把我从厦门送回家去，他也给我开过一个方子呢，是否贻误就不得而知了，反正在车上，我只知道两眼模糊，浑身无处不疼痛，胸闷欲吐，每个毛孔都在冒烟，一路往黄泉路上奔去，英雄人物所受的大刑也大抵如此，只等着赶快见到家人最后一面。我记得自己是被拉下车来的，后来晃晃悠悠被送到一个农村的老家伙那里，她两手在我身上东抓西捏一把，好像点穴一般，再吃了两个小白片，总算把我从黄泉路上拦了回来，好像才花了两块钱（人命两块钱一条而已，真难为我那老父老母从那找来的宝贝人物）。但事情并没有完，以后的日子里，每天要在伤口上敷药－－好像是白花蛇舌草（水边生开小白花的东东，好的未必是名贵的）绞汁掺珍珠粉（养颜哪），到了晚上撕心裂肺的疼，但至少是清醒的，没办法睡，我就在房间里蹑手蹑脚的踱来踱去，直到天亮，老妈还以为我居然变得勤奋好学了－－清晨我就在阳台上装模作样的看书了。以后看武侠小说，忽然有种似曾相似的感觉（艰难要死－－遇上神人－－，特别是赤脚医生那两下子，简直就是武林大侠在世），但我终究没有那么好的运气练成什么盖世奇功，但是在学校里时却有个会耍刀的人叫我为‘大侠’真是奇怪哉。
<br>一年和表哥去爬‘玳瑁山’（好像福建有好几座，到底是那一座呢），走的是乱七八糟的路，反正前无古人、后无来者，衣服裤子割得一道道，又饿又饥，面前一块巨岩，找不到出路，心里一横，就从这里上。踩在表哥肩上抓着石缝上了一段距离，到后来却是难上难下，前面是一棵到了根部也只有拇指粗的小树，退后是不可能的，可恶的是那块石头居然是挑出来的，低头望去，云层的影子在绸缎般的大地上游动着，大片的阴影向我们飘来，人好像挂在千丈崖上，两腿战战，走投无路（就像《战争子午线》中那个挂在悬崖上的小孩子），当时真想大哭起来－－摔死在这里十年八年也没人知道啊。那棵不起眼的小杜鹃到底是救了我们一命，大自然跟我们开了个不大不小的玩笑，再上来一段就是最顶峰的那块石头，奇怪的是山顶上绿草茵茵，平整得象草原一样，而几秒中之前我还看不到生存的希望。虽然饿了一天，只有山泉充饥，从山上下来已经伸手不见五指（是没有一点灯光的那种黑，远处的灯火和天上的星星一样遥远），但是我很满足，山颠那道风景是我见到的最遥远、最畅快的风景，她简直改变了我的世界观。
<br>还有很多的事情让我可以和死亡亲密接触：在九龙江里游泳，一脚踩到松沙，滑到了不见底的航道里，而我不会游泳，好像只有等死，一支大手把我托了上来，那是我的父亲，当时夕阳照着圆山映在江面上，红红的还真好看。
<br>当我还在房地产公司的时候我常驻现场，常和那些年青的施工员、民工接触－－白天还在办公室里吵架，晚上就一起到工棚里或者躺在飘着油墨香的模板台面上值班，伴随着隆隆的混凝土的泵送声和嗡嗡的振棒声大声的聊天，令我惊奇的是他们每个人曾都或多或少的直面身边的死亡，谈起来津津有味的样子。其实危机就时刻潜伏着。有一天晚上，穿过大型的打桩机，看不见上面，只看到黑黑大铁架，忽然叮当一声巨响，不知什么东西掉了下来，一阵乱响之后，一块铁件砸在不远处，当时没在意，后来才知道，桩机上有人已经受伤了，幸亏没掉下来，要知道那桩机有十几层楼高，而他们就在顶上搞维修呢。封顶以后，有一天，我急匆匆的去核实电路，从a座到b座约22米，中间有个联络通道，高度25m就是8层左右的样子。走的急也就不是十分在意看踏板的铺设，忽然一脚就空了，整个人往下一沉，幸亏有那么一点太极拳的基础，两手一伸抓住侧杆（如果是侧板就完了），另一只脚座在中间杆上（如果没有中杆，那也玩完了），看见那块倒霉的跳板，正以跳水运动员的优美姿势在空中翻动着，底下没有安全网，很快就听到它撞在脚手架上的声音，缤缤梆梆响个不停，震动从脚手架上传来，力道不小，要是人当时下去，非变成好几段不可。呓！想来就后怕。从此我就懒得去用那个通道。但是有一天，那个负责浇模养护的老头却在凌晨时分，从自己的岗位上掉了下去再也没上来，可怜他那么老了还在打工。每当我从这座美丽的花园前走过，我常会忍不住要去抬头看看那个‘空中通道’尽管它已不在了好久。
<br>一个人要活着还真不容易，两个人要相遇也很不容易。世间有太多的变数，给你一万次的机会，即使每次的成功率是99.9999％（24k金：），您也会发现生存下来简直就是一个可以忽略不计的小概率事件，说了这么多废话，就是说，我能够生存也只是侥幸而已，大概其他人也差不多吧。生存尚且如此，其他就更加不可琢磨吧，何必动辄谈生论死呢（我有一个只见一面的朋友，居然自杀了，大大的不爽），老子看了就有气－－‘我砍，砍掉你这个歪念头！但留下你这个美丽而笨蛋的头’', '以为咖啡早就不存在了，没想到是换了一个名字，也就是说，它只是换了一个存在方式而已。

但是一上来就看到这里有人要生要死的。嗯，生存还是死亡，的确是个问题。但是我还是大家能活下去，那怕稀里糊涂也好。‘你不是我怎知我错’一定有人感觉不爽，其实我也不爽，我自己也找不到天堂之路嘛。

